  import java.io.FileInputStream;
  import java.io.FileNotFoundException;
  import java.io.IOException;
  import java.util.Scanner;

  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  import sailpoint.api.Provisioner;
  import sailpoint.api.SailPointContext;
  import sailpoint.object.Identity;
  import sailpoint.tools.GeneralException;
  import sailpoint.tools.Util;
  import sailpoint.api.ObjectUtil;
  import sailpoint.tools.Message;
  import sailpoint.object.QueryOptions;

  import java.text.SimpleDateFormat;

  public String formateDateString(String dateStr){
    String result = "";
    try{

      result = convertDateToString(dateFormater.parse(dateStr));
    }catch(Exception e){
      logger.error("Exceptin in formateDateString : "+e.getMessage());
    }
    return result;
  }

  public String formateDOB(String dateStr){
    String result = "";
    try{
      result = dateFormaterDOB.format(dateFormater.parse(dateStr));

    }catch(Exception e){
      logger.error("Exceptin in formateDOB : "+e.getMessage());
    }
    return result;
  }


  public void  updateIdentity(Map feedMap){
    boolean isNewIdentityCreated = false;
    boolean isIdentityUpdated = false;
    Identity avatarIdentity = null;
    Identity managerIdentity = null;
    Identity contractorManIdentity = null;
    QueryOptions qo = new QueryOptions();
    String internalId = "";
    String initialName = "";
    if(feedMap!=null && !feedMap.isEmpty()){
      try{

   
        if(feedMap.get(pivotColumn)!=null){

          qo.addFilter(Filter.ignoreCase(Filter.eq(pivotColumn, feedMap.get(pivotColumn))));
          Iterator itr = context.search(Identity.class,qo);

         

          if(!Util.isEmpty(itr) &&  itr.hasNext()){
            //get the identity
            
			avatarIdentity = ((Identity)itr.next());
            Util.flushIterator(itr);
          }else{
            // create new identity
            avatarIdentity = new Identity();

            isNewIdentityCreated = true;

            initialName = initialUserName();
            avatarIdentity.setName(initialName);

            internalId = generateNextSailpointInternalIdentifier();
            avatarIdentity.setAttribute("internalId", internalId);

            avatarIdentity.setManager(defaultManager);
            avatarIdentity.setAttribute("avatarId",feedMap.get(pivotColumn)); 
            avatarIdentity.setAttribute("type", "non-hr contractor");

          }

       


          if(avatarIdentity!=null ){  //  confirm inactive check
			// update comman attribute
			avatarIdentity.setAttribute("domain", "AMITA");
			avatarIdentity.setAttribute("ministry", "AMITA Health");

            for(String attributeName : feedMap.keySet()){
              if(pivotColumn.equalsIgnoreCase(attributeName)){
                continue;
              }
              if(attributeName.equalsIgnoreCase(manager)){
                managerIdentity = context.getObjectByName(Identity.class, feedMap.get(attributeName) );
                if(managerIdentity!=null ){
                  avatarIdentity.setManager(managerIdentity);

                }else{                  
                  errorListSet.add(feedMap.get(attributeName)+" = invalid manager");
                }
              }else if(attributeName.equalsIgnoreCase(contractorManager)){
                contractorManIdentity = context.getObjectByName(Identity.class, feedMap.get(attributeName));
                if(contractorManIdentity!=null ){
                  avatarIdentity.setAttribute(attributeName,feedMap.get(attributeName));
                }else{
                  errorListSet.add(feedMap.get(attributeName)+" = invalid contractorManager");
                }
              }else if(attributeName.equalsIgnoreCase(hireDate)){
                resultString = "";
                resultString = formateDateString(feedMap.get(attributeName));

                avatarIdentity.setAttribute(attributeName,resultString);
              }else if(attributeName.equalsIgnoreCase(ctrexpDt)){
                resultString = "";
                resultString = formateDateString(feedMap.get(attributeName));

                avatarIdentity.setAttribute(attributeName,resultString);
              }else if(attributeName.equalsIgnoreCase(dob)){
                resultString = "";
                resultString = formateDOB(feedMap.get(attributeName));
                if( Util.isNotNullOrEmpty(resultString) ){
                  resultString = encryptAES(resultString);
                }

                avatarIdentity.setAttribute(attributeName,resultString);
              }else if(attributeName.equalsIgnoreCase(ssn)){
                resultString = feedMap.get(attributeName);
                if( Util.isNotNullOrEmpty(resultString) ){
                  resultString = encryptAES(resultString);
                }

                avatarIdentity.setAttribute(attributeName,resultString);
              }else{
                avatarIdentity.setAttribute(attributeName, feedMap.get(attributeName));
              }
            }
			//set protected to prevent deletion
			
			avatarIdentity.setProtected(true);
			
            context.saveObject(avatarIdentity);
            if(isNewIdentityCreated){
              
              identitiesCreated.add(feedMap.get(pivotColumn));
            }else{
              
              identitiesUpdated.add(feedMap.get(pivotColumn));
              isIdentityUpdated = true;
            }

          }else{
            errorListSet.add(feedMap.get(pivotColumn)+" = invalid Identity");
            identitiesNotUpdated.add(feedMap.get(pivotColumn));
          }
        }

      }catch(GeneralException e){
    
        logger.error("error in update user "+e.getMessage());
        taskResult.addMessage(new Message(Message.Type.Warn,feedMap.get(pivotColumn)+ " : GeneralException : "+e.getMessage(), null));
        errorListSet.add(feedMap.get(pivotColumn));
      }catch(Exception e){
       
        logger.error("error in update user "+e.getMessage());
        taskResult.addMessage(new Message(Message.Type.Error,"Exception : "+e.getMessage(), null));
        errorListSet.add(feedMap.get(pivotColumn));
      }
    }
  }


  public List delimToList(String delimiter,String lineString){
    List result = new ArrayList();
    if(Util.isNotNullOrEmpty(lineString)){
      if(Util.isNotNullOrEmpty(delimiter) && delimiter.equals(",")){
        List tempList = Util.csvToList(lineString);
        for(String str : tempList){
          if(Util.isNullOrEmpty(str)){
            str = "";
          }
          result.add(str.trim());
        }
      }else{
        String []str = lineString.split(delimiter);
        for(String s : str){
          if(Util.isNullOrEmpty(s)){
            s = "";
          }
          result.add(s.trim());
        }
      }
    }
    return result;
  }

  /* Starts point  */
  
  Log logger = LogFactory.getLog("Ascension-Rule-Migration-CreateOrUpdateAvatar");
  logger.debug("Ascension-Rule-Migration-CreateOrUpdateAvatar Start");

  Set errorListSet = new HashSet();

  Set identitiesUpdated = new HashSet();
  Set identitiesNotUpdated = new HashSet();
  Set identitiesCreated = new HashSet();

  String manager = "manager";
  String contractorManager = "contractorManager";
  String pivotColumn = "avatarId";
  String dob = "dob";
  String hireDate	 = "hireDate";
  String ctrexpDt = "ctrexpDt";
  String resultString = "";
  String ssn = "ssn";

  SimpleDateFormat dateFormater = new SimpleDateFormat("MM/dd/yyyy");
  SimpleDateFormat dateFormaterDOB = new SimpleDateFormat("MM/dd");



  String DELIMITER = ",";
  String inputFileName = "";
  boolean isHeader = true;
  String lineString ="";
  FileInputStream inputFile = null;
  Scanner scanner = null;
  List headerList = new ArrayList();
  List dataList = new ArrayList();
  int inputRecordCounter = 0;
  Map feedMap =null;
  String managerName = "";
  Identity defaultManager = null;
  try {

    if(config!=null){
      inputFileName = config.get("filePath");
      pivotColumn = config.get("pivotColumn");
      managerName = config.get("managerName");
    }
    if(Util.isNotNullOrEmpty(managerName)){
      defaultManager = context.getObjectByName(Identity.class,managerName);
    }
    if(defaultManager==null){
      throw new GeneralException("Selected workgorup is invalid.");
    }

 
    inputFile = new FileInputStream(inputFileName);

    scanner = new Scanner(inputFile); 

    while (scanner!=null && scanner.hasNextLine()) {
      lineString = scanner.nextLine();
      if(Util.isNotNullOrEmpty(lineString)){
        if(isHeader){
          isHeader = false;
          headerList = delimToList(DELIMITER , lineString);
          continue;
        }
        inputRecordCounter++;
        feedMap = null;
        feedMap = new HashMap();
        int counter = 0;
        for( String col : headerList){
          dataList = delimToList(DELIMITER , lineString);
          if(dataList!=null && dataList.size() == headerList.size()){

            if(Util.nullSafeCaseInsensitiveEq(dataList.get(counter), "null") ||  Util.isNullOrEmpty(dataList.get(counter)) ){
              feedMap.put(col, "");
            }else{
              feedMap.put(col, dataList.get(counter));
            }
          }
          counter++;
        }

        if(feedMap !=null){
          updateIdentity(feedMap);
		  if(inputRecordCounter%1000==0){
          context.commitTransaction();
			}
        }
      }
    }
    context.commitTransaction();
 
  }catch (FileNotFoundException e) {
    logger.error("Exception in update user "+e.getMessage());
    taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
   
  }catch (GeneralException e) {
    logger.error("Exception in update user "+e.getMessage());
    taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
 
  }finally{
    if(scanner!=null){
      scanner.close();
    }
    if(inputFile!=null){
      try {
        inputFile.close();
      } catch (IOException e) {
        logger.error("Exception in "+e.getMessage());
        taskResult.addMessage(new Message(Message.Type.Error, "Exception: "+e.getMessage(), null));
      }
    }
    context.commitTransaction();
  
  }

  taskResult.setAttribute("identitiesCreated",identitiesCreated);
  taskResult.setAttribute("identitiesUpdated",identitiesUpdated);  
  taskResult.setAttribute("identitiesNotUpdated",identitiesNotUpdated);  
  taskResult.setAttribute("identitiesErrors",errorListSet);
  taskResult.setAttribute("inputRecordCounter",inputRecordCounter);


  
  logger.debug("Ascension-Rule-Migration-CreateOrUpdateAvatar End");
  return "";
